import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Button,
  Select,
  DateRangeFilter,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  type DateRangeValue,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { AttendanceRecordDto, DepartmentDto } from '../../../services/ns/models';
import { baoCaoDiTrePageLabels as labels } from '../../../constants/baoCaoDiTrePageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useHrAttendancePermissions } from '../../../hooks/useHrPermissions';
import { formatDateLocal } from '../../../utils/format';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-bao-cao-di-tre';
const PAGE_ID = 'ns-bao-cao-di-tre';

type ViewMode = 'summary' | 'detail';

interface SummaryRow {
  employeeId: string;
  employeeName: string;
  lateTimes: number;
}

function aggregateByEmployee(rows: AttendanceRecordDto[]): SummaryRow[] {
  const map: Record<string, SummaryRow> = {};
  for (const r of rows) {
    if (!map[r.employeeId]) {
      map[r.employeeId] = { employeeId: r.employeeId, employeeName: r.employeeName, lateTimes: 0 };
    }
    if (r.isLate) map[r.employeeId].lateTimes += 1;
  }
  return Object.values(map).filter(x => x.lateTimes > 0);
}

const BaoCaoDiTrePage: React.FC = () => {
  const dispatch = useAppDispatch();
  const perms = useHrAttendancePermissions();
  const now = new Date();
  const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
  const monthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().slice(0, 10);

  const [fromDate, setFromDate] = useState(monthStart);
  const [toDate, setToDate] = useState(monthEnd);
  const [departmentId, setDepartmentId] = useState('');
  const [view, setView] = useState<ViewMode>('summary');
  const [depts, setDepts] = useState<DepartmentDto[]>([]);
  const [rows, setRows] = useState<AttendanceRecordDto[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      hrService
        .getDepartments()
        .then(d => {
          if (!cancelled) setDepts(d);
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, []);

  const handleLoad = useCallback(() => {
    setLoading(true);
    hrService
      .getLateReport({ fromDate, toDate, departmentId: departmentId || undefined })
      .then(res => setRows(res.items))
      .catch(err => {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, labels.loadError),
          type: 'error',
        });
      })
      .finally(() => setLoading(false));
  }, [dispatch, fromDate, toDate, departmentId]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (!cancelled) handleLoad();
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [handleLoad]);

  const handleExport = useCallback(() => {
    const qs = new URLSearchParams({ fromDate, toDate });
    if (departmentId) qs.set('departmentId', departmentId);
    const a = document.createElement('a');
    a.href = `${import.meta.env.VITE_API_URL}/hr/attendance/late-report/export-excel?${qs}`;
    a.download = 'BaoCaoDiTre.xlsx';
    a.click();
  }, [fromDate, toDate, departmentId]);

  const { showTableLoading } = useCatalogTableBusy(loading);
  const summaryRows = aggregateByEmployee(rows);
  const detailRows = rows.filter(r => r.isLate);
  const displayRows = view === 'summary' ? summaryRows : detailRows;
  const hasData = displayRows.length > 0;

  const headerHint = useMemo(() => {
    if (rows.length === 0) return undefined;
    const lateCount = rows.filter(r => r.isLate).length;
    return view === 'summary'
      ? `${summaryRows.length} nhân viên · ${lateCount} lần đi trễ`
      : `${detailRows.length} ${labels.itemLabel}`;
  }, [rows.length, view, summaryRows.length, detailRows.length]);

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-date`,
        content: (
          <DateRangeFilter
            fromDate={fromDate}
            toDate={toDate}
            onChange={(v: DateRangeValue) => {
              setFromDate(v.fromDate ?? '');
              setToDate(v.toDate ?? '');
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-dept`,
        content: (
          <Select
            label={labels.deptLabel}
            value={departmentId}
            onChange={e => setDepartmentId(e.target.value)}
            options={[
              { value: '', label: labels.deptAll },
              ...depts.map(d => ({ value: d.id, label: `${d.code} — ${d.name}` })),
            ]}
            fullWidth
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-view`,
        content: (
          <Select
            label={labels.viewModeLabel}
            value={view}
            onChange={e => setView(e.target.value as ViewMode)}
            options={[
              { value: 'summary', label: labels.viewSummary },
              { value: 'detail', label: labels.viewDetail },
            ]}
            fullWidth
          />
        ),
      },
      {
        testId: `${TEST_ID}-view-btn`,
        content: (
          <Button
            variant="primary"
            onClick={handleLoad}
            loading={loading}
            data-testid={`${TEST_ID}-view-btn`}
          >
            {labels.view}
          </Button>
        ),
      },
      ...(perms.canRead
        ? [
            {
              testId: `${TEST_ID}-export-btn`,
              content: (
                <Button
                  variant="secondary"
                  onClick={handleExport}
                  disabled={rows.length === 0}
                  data-testid={`${TEST_ID}-export-btn`}
                >
                  <i className="fas fa-file-excel" /> {labels.exportAction}
                </Button>
              ),
            },
          ]
        : []),
    ],
    [fromDate, toDate, departmentId, depts, view, handleLoad, loading, handleExport, perms.canRead, rows.length],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: handleLoad,
      canChart: false,
      canPrint: hasData,
      onPrint: () => window.print(),
    }),
    [handleLoad, hasData],
  );

  const listBody =
    !showTableLoading && !hasData ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{view === 'summary' ? labels.empty : labels.emptyDetail}</p>
      </div>
    ) : !showTableLoading && view === 'summary' ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>{labels.colName}</th>
              <th className={erp.colRight}>{labels.colLateCount}</th>
            </tr>
          </thead>
          <tbody>
            {summaryRows.map(r => (
              <tr key={r.employeeId} data-testid={`${TEST_ID}-row-${r.employeeId}`}>
                <td>{r.employeeName}</td>
                <td className={erp.colRight}>
                  <span className={erp.tagWarning}>{r.lateTimes}</span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>{labels.colDate}</th>
              <th>{labels.colName}</th>
              <th>{labels.colStatus}</th>
            </tr>
          </thead>
          <tbody>
            {detailRows.map(r => (
              <tr key={r.id} data-testid={`${TEST_ID}-row-${r.id}`}>
                <td>{formatDateLocal(r.attendanceDate)}</td>
                <td>{r.employeeName}</td>
                <td>
                  <span className={erp.tagWarning}>{labels.statusLate}</span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-user-clock',
          pageId: PAGE_ID,
          hint: headerHint,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.listTitle}
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default BaoCaoDiTrePage;
